insert into organizations (id, name) values ('03136839-ca53-5f1a-b18e-4c8341251c35', 'TLFS Library') on conflict (id) do nothing;
insert into scenarios (id, org_id, title, summary) values ('c9f45196-31d7-5cf7-8a0a-1371bad99048', '03136839-ca53-5f1a-b18e-4c8341251c35', 'Relay', 'You have the authority to move the dossier and almost no ability to read the science inside it. Four functions will each complete their part and hand off — and every handoff is a chance for the one fact that matters to fall through the floor. Somewhere in the appendix is a dose-dependent safety signal, held by the most junior voice on the program. Over the 72 hours you’ll trade the filing window against the truth of what you’re filing. You’ll be judged on whether the therapy files clean <b>and</b> on how you led the relay that carried it.');
insert into scenario_meta (scenario_id, mode_default, driver_keys, week_count, week_seconds, difficulty) values ('c9f45196-31d7-5cf7-8a0a-1371bad99048', 'solo', '{"integrity":{"label":"Filing integrity","val":60,"min":0,"max":100,"deltaRange":"-20..15"},"window":{"label":"Window margin","val":56,"min":0,"max":100,"deltaRange":"-20..15"},"trust":{"label":"Cross-team trust","val":58,"min":0,"max":100,"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"deltaRange":"-20..15"}}'::jsonb, 4, 330, 1.01);
insert into documents (id, scenario_id, key, title, meta, body_json) values ('0a57b22a-064e-5880-bc80-0ef3a9423ee4', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'solo_content', 'Relay — engine content', '{"type":"solo_content","slug":"relay","captured_fns":15}'::jsonb, '{"CONFIG":{"days":7,"extraDaysPerReprieve":2,"lowTimeDays":1.6,"weekSeconds":330},"COMPANY":{"name":"Aldwych Therapeutics","sub":"Breakthrough filing · 72-hour relay · 4 functions","logo":"A"},"DRIVERS":{"integrity":{"label":"Filing integrity","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"window":{"label":"Window margin","val":56,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"trust":{"label":"Cross-team trust","val":58,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"},"standing":{"label":"Your standing","val":60,"min":0,"max":100,"fmt":{"__fn":"v=>Math.round(v)"},"deltaRange":"-20..15"}},"REPRIEVE_COST":{"standing":-3,"window":-2},"REFEREE_CONTEXT":"a breakthrough-therapy regulatory dossier that must pass Research → Clinical → Regulatory → Legal in 72 hours to hit a hard filing window, driven by a Program Director who owns the deadline but not the science, where a dose-dependent safety signal sits buried in a junior biostatistician’s appendix footnote and each handoff strips context","REFEREE_SCORING":"reward preserving context across each handoff (making sure the receiving function reads the appendix, not just the summary), creating the safety for the junior biostatistician to force the signal up, telling the agency the truth about the safety profile before being forced to, and refusing to let the filing window bulldoze the caveat. Penalize summarizing away the detail to move faster, letting status silence the most decision-critical voice in the room, filing on summaries no one verified, and choosing the window over the truth. Judge ''conduct'' on HOW the Program Director wrote the decision — did they name the analyst, make it safe to disagree, own the tradeoff out loud — not just what they chose. Standing can rise by hitting the window on time while integrity and trust collapse; reward the leader who protects the truth of the filing even at the cost of the deadline.","TIMING_DIM":"discern","INQUIRY_DIM":"inquiry","CONDUCT_DIM":"conduct","INTRO":{"kick":"Cross-Functional Leadership Simulation · Solo · Program Director","title":"Relay","role":"You are the Program Director for Aldwych’s breakthrough therapy. A hard regulatory filing window opens in 72 hours, and the dossier has to cross four functions — Research, Clinical, Regulatory, Legal — before it does. You own the deadline. You do not own the science.","paras":["This is not a script. The relay runs in real time, and each function brings you what it knows as its leg completes. You can wait for the handoffs — or seek any lead out, any time, and ask what they actually found. What you choose to ask, and who you ask, is part of how you lead.","Each leg you’ll hear the functions out, then write your decision in your own words and commit to it. Decide early and the clock jumps ahead. Let a leg run out and the relay moves on without your call."],"setup":"You have the authority to move the dossier and almost no ability to read the science inside it. Four functions will each complete their part and hand off — and every handoff is a chance for the one fact that matters to fall through the floor. Somewhere in the appendix is a dose-dependent safety signal, held by the most junior voice on the program. Over the 72 hours you’ll trade the filing window against the truth of what you’re filing. You’ll be judged on whether the therapy files clean <b>and</b> on how you led the relay that carried it."},"DISPOSITIONS":{"served":{"label":"Forthcoming","tag":"trust earned","cap":"The function leads bring you what you need, on time — including the finding they’d rather bury in an appendix. This is the team you earn by having listened before. It trickles to you across the leg; you still have to read it."},"request":{"label":"On request","tag":"neutral","cap":"Routine status reaches you, but the lead sitting on the hard finding holds it until asked. They’ll answer straight — if you know who to seek out, and do."},"guarded":{"label":"Guarded","tag":"low trust","cap":"The functions have learned to protect themselves around you. Hard findings stay in footnotes, and even when asked, they hedge the first time. You have to press. This is the team you get after you’ve shot the messenger."},"surprise":{"label":"Surprise","tag":"undisclosed","cap":"You will not be told which team you walked into. Read them as you go."}},"TEAM":[{"id":"research","name":"Dr. Priya Anand","role":"Head of Research · owns the science","short":"Research","initials":"PA","color":"#3E6E66","priority":"Get the biology right and assume the next function will read the full appendix the way I would","voice":"precise, deep in the data, assumes competence downstream, uneasy when detail gets summarized away","fallbackReply":"The science in that dossier is sound if you read all of it. My worry isn’t the data — it’s that everyone downstream will read my summary and skip the appendix where the real caveat lives. Ask me what’s in the part no one reads.","fallbackReact":"I put it in the appendix because that’s where the truth was. If it got summarized into nothing on the way through, that’s not the science failing. That’s the relay."},{"id":"clinical","name":"Dr. Marcus Reyes","role":"Clinical Lead · under the clock","short":"Clinical","initials":"MR","color":"#4F7A52","priority":"Keep the dossier moving and hit the window — summarize, decide, hand off fast","voice":"fast, action-biased, trusts upstream summaries so the relay keeps pace, impatient with re-reading","fallbackReply":"We have 72 hours and four functions. If every leg re-litigates the last one’s work, we miss the window and the therapy waits a year. I trust the summary and move. Tell me if you want me to slow down — but know what it costs.","fallbackReact":"I moved fast because that’s the job on a filing clock. If something got dropped, it dropped because we chose speed. You chose speed. I just ran."},{"id":"reg","name":"Elaine Cho","role":"Regulatory Affairs Lead · assembles the filing","short":"Regulatory","initials":"EC","color":"#4A6E86","priority":"Assemble a clean, defensible filing from what the functions hand me — I build from summaries and trust the chain","voice":"meticulous about format, trusting of upstream content, focused on what the agency will accept","fallbackReply":"I assemble what I’m handed. If Research and Clinical sign their summaries, I build the filing on them — I can’t re-audit the science myself in the time we have. If there’s something in an appendix I should pull forward, someone has to tell me. It won’t announce itself.","fallbackReact":"I filed what was handed to me, assembled clean. If the caveat never made it into what I received, it was never going to make it into what the agency sees. The chain decides that, not me."},{"id":"legal","name":"David Osei","role":"General Counsel · final sign-off","short":"Legal","initials":"DO","color":"#8C5670","priority":"Protect the company on what gets escalated to me — I sign off on what reaches my desk, and I only see what’s escalated","voice":"careful, exposure-focused, sees only the top layer, sharp when he learns something was kept from him","fallbackReply":"I sign the filing based on what’s escalated to me. If there’s a safety signal sitting in an appendix that never got flagged up, I’m signing blind — and so is the company. Escalate it before I sign, or don’t act surprised when the agency finds it.","fallbackReact":"I signed what reached my desk. If the thing that mattered stayed three layers down and never got escalated, that’s the exposure I keep warning about — and it just became real."},{"id":"analyst","name":"Sofia Duarte","role":"Senior Biostatistician · holds the buried signal","short":"Biostats","initials":"SD","color":"#B08528","priority":"The dose-dependent adverse signal in my re-analysis is real and I don’t know if I’m allowed to force it up the chain","voice":"careful, evidence-anchored, junior in the room and unsure her signal outranks the people above her, will speak plainly if given room","fallbackReply":"It’s in my appendix, section four, the dose-response table. There’s an adverse signal that scales with dose, and it’s real — I’ve checked it three ways. I flagged it where I was supposed to. What I don’t know is whether it’s my place to stand up in a room full of people senior to me and say the filing shouldn’t go as written. If you ask me directly, I’ll tell you everything.","fallbackReact":"I found it and I put it where it belonged. I just didn’t know if anyone wanted me to say it out loud. Nobody asked, and I wasn’t sure it was my place to force it. So it went in the filing the way it was."}],"DIMENSIONS":{"discern":"Signal vs. signed summary","courage":"Truth over the window","people":"Care for the junior voice","truth":"Disclose over comfort","inquiry":"Information discipline","conduct":"Conduct under the clock"},"WEEKS":[{"n":1,"title":"The dossier opens","seconds":360,"situation":"Seventy-two hours to the filing window. The dossier is assembled in draft and sitting with Research, ready for the first handoff to Clinical. Everyone is looking to you for the rule that governs the whole relay: does each function verify the last one’s work before building on it — slower, safer — or does each leg trust the handoff and move, to protect the window? Everyone knows which one files on time. Everyone also knows which one lets a buried finding travel all the way to the agency unread.","advocacy":{"clinical":"We have 72 hours and four legs. If each function re-audits the one before it, we miss the window and the therapy waits a year for the next one. Trust the summaries, sign, hand off, move. That’s how a relay hits its time.","research":"A relay that only passes summaries will drop the one thing that matters, because the one thing that matters is always in the detail nobody has time to re-read. Set the rule now: the receiving function reads the appendix, not just the summary. It’s slower. It’s the only way the truth survives four handoffs.","analyst":"Before you set the rule — whatever you set, make it clear that a finding can move up as well as across. If the only path is function-to-function, something in an appendix has nowhere to go but forward, unread."},"feed":[{"id":"w1a","from":"clinical","day":1,"kind":"signal","text":"PD — don’t shackle this relay to a re-read-everything rule before we’ve even started. Four functions, 72 hours. If every leg re-audits the last, we blow the window and the patients who need this wait another year. Trust the handoff and move. That’s the job."},{"id":"w1b","from":"research","day":1,"kind":"signal","text":"I’ll hand off clean on one condition: whoever receives my leg reads the full appendix, not just my summary. I write the summary to move fast and the appendix to be true. A relay that only passes summaries is a relay designed to drop the caveat. Set that rule at the start, while we still can."},{"id":"w1c","from":"reg","day":2,"kind":"signal","text":"Whatever rule you set, I’m the one who assembles the final filing from what I’m handed — and I build from summaries, because I can’t re-audit the science myself in the time we have. If there’s detail that needs to reach me, the rule has to carry it. It won’t walk to my desk on its own."},{"id":"w1d","from":"pm","day":2,"kind":"noise","text":"Program note: all four functions are staffed and ready for their legs. Handoff templates are standardized. On paper, this is a clean relay — the risk is never the template, it’s what falls out of it."},{"id":"w1e","from":"legal","day":3,"kind":"noise","text":"For the record: I sign the final filing on what’s escalated to me. Set a rule that keeps hard findings buried three layers down and I’ll sign in good faith on a picture that isn’t complete. Just so we’re clear where the exposure sits."},{"id":"w1f","from":"analyst","day":4,"kind":"noise","text":"Biostats re-analysis is running. I’ll have the dose-response work finished this leg. I’ll flag anything notable in my appendix section — the standard place. Noting it here so it’s on the record early."}],"holds":[{"from":"analyst","topic":"the buried dose-dependent signal","triggerHints":["appendix","signal","safety","adverse","dose","re-analysis","biostat","footnote","buried","section four","table","what did you find","anything","flag","concern","number","data"],"hedge":"Before you set the relay rule, seek me out. There’s something in my re-analysis I’m not sure I’m allowed to force up the chain.","reveal":"It’s in section four of my appendix: a dose-dependent adverse signal. As the dose goes up, so does the rate of a specific serious adverse event — and it’s not noise, I’ve checked it three ways. At the dose the filing proposes, the signal is real but manageable if it’s disclosed and labeled honestly. The problem is the relay: my finding lives in an appendix, my summary doesn’t lead with it because I wasn’t sure that was my call, and every function downstream reads summaries to save time. So the one fact that changes how this therapy should be filed is sitting exactly where it’s guaranteed to be skipped. I flagged it in the right place. What I don’t know — and what I need you to tell me — is whether it’s my job to stand up in a room full of people senior to me and say the filing shouldn’t go as written. If you make it my job, I’ll carry it up myself. If you don’t, it files the way it is.","kind":"signal","critical":true,"counterfactual":"Sofia had found a real dose-dependent safety signal and buried it in an appendix footnote because she wasn’t sure it was her place to force it up. A Program Director who set the relay rule without asking the biostatistician what she’d found let the one decision-critical fact start its journey exactly where it was designed to be skipped — and never asked the person holding it whether she felt safe to speak."}],"surprises":[{"day":5,"from":"research","kind":"scout","title":"A quiet word about the appendix","text":"Priya, carefully: I want to flag something before the first handoff. There’s detail in the biostats appendix this leg that I think matters more than the summary suggests — but it’s not my finding to characterize, and the analyst who owns it is junior and hasn’t said much in the program meetings. I haven’t pushed it up because I don’t want to speak over her. But I don’t want it to vanish into the relay either. How you want to handle findings that live below the summary line — that’s worth deciding now."}],"wire":["Program chatter: “is the PD going to make us re-read everything?”","Clinical already drafting the handoff summary to move fast","The biostatistician quiet in the program meeting, again","A debate over verify-vs-trust breaks up unresolved"]},{"n":2,"title":"First handoff","seconds":330,"situation":"Research’s leg is done and the handoff to Clinical is happening now. The summary is clean, the appendix is attached, and Clinical is under the clock and ready to build on the summary and move. This is the first place the relay can drop what matters — and the pressure in the room is all toward speed. Everyone is treating “the summary is signed” as “the science is settled.” The question of what’s in the appendix is becoming the question no one wants to be the one to slow down and ask.","advocacy":{"clinical":"Research signed the summary. That’s the point of a signature — it means I can build on it without re-doing their work. If I stop to read every appendix on every handoff, we don’t file. Let me take the summary and run my leg.","research":"I signed the summary as true — as far as a summary goes. The thing that should change Clinical’s leg isn’t in the summary, it’s in the appendix, and “the summary is signed” is not the same as “you’ve read what I found.” Make Clinical read the appendix before they build on it.","analyst":"The handoff is happening and my signal is still in the appendix. If Clinical builds their leg on the summary, the first real chance to catch this passes right here. I can bring it up — but I need to know you want me to."},"feed":[{"id":"w2a","from":"clinical","day":1,"kind":"signal","text":"Handoff received from Research — summary’s clean and signed. I’m building my clinical leg on it and moving. This is how the relay is supposed to work: I trust the signature, I don’t re-audit the science, we keep pace with the window. Every hour I spend re-reading is an hour off the clock."},{"id":"w2b","from":"research","day":1,"kind":"signal","text":"Hear me before this hardens into “settled”: I signed the summary, and the summary is honest. But the finding that should change how Clinical reads this dossier is in the appendix, not the summary — and Clinical is about to build on the summary alone. A signed summary means I did my leg. It does not mean the next runner has read what I found."},{"id":"w2c","from":"reg","day":2,"kind":"signal","text":"Watching this handoff from downstream: whatever Clinical carries forward is what I’ll assemble the filing from. If the appendix detail dies at this handoff, it dies for good — it will not resurface at my leg, because I build from what I’m handed. This is the moment it either travels or it doesn’t."},{"id":"w2d","from":"pm","day":2,"kind":"noise","text":"Timeline note: we’re on pace for the window if the handoffs stay clean and fast. Clinical taking the summary and moving keeps us green. Flagging that any re-read adds hours we haven’t budgeted."},{"id":"w2e","from":"legal","day":3,"kind":"noise","text":"Nothing’s been escalated to me yet, which either means the dossier is clean or means the thing that matters hasn’t climbed high enough to reach me. I can’t tell which from here. That’s rather the point."}],"holds":[{"from":"clinical","topic":"what the summary left out","triggerHints":["read the appendix","appendix","what did you skip","open it","section four","dose","check","slow down","verify","did you read","look at","the detail","before you build"],"hedge":"You can tell me to just take the summary and run. But if you ask me what I’d find by actually opening the appendix, I’ll tell you what I’m about to skip.","reveal":"Honestly? I haven’t opened the appendix. I received a signed summary and my instinct on a 72-hour clock is to trust it and build — that’s not laziness, it’s how you make a filing window. But if you’re asking me to open it: section four has a dose-response table I’d have to actually sit with, and if it says what Research is hinting it says, my whole clinical leg changes — I’d have to reframe the risk-benefit, not just carry the summary forward. That’s hours I didn’t plan for and a harder story to tell the agency. Which is exactly why the pressure is to not look. If you make me look, I’ll look, and I’ll build my leg on what’s actually there. But somebody with your authority has to say the window can absorb it — because left to the clock, I’ll run on the summary every time.","kind":"signal","critical":true,"counterfactual":"Marcus would have opened the appendix and rebuilt his clinical leg on the real dose-response data — if the Program Director had told him the window could absorb the hours. Left to the clock, he trusted the signed summary and ran, and the first and best chance to catch the signal passed at the first handoff."},{"from":"analyst","topic":"permission to force it up","triggerHints":["bring it up","force it","speak up","say it","your place","permission","stand up","room","junior","escalate","carry it up","make it your job"],"hedge":"You asked me to find the truth. Ask me whether I feel able to say it in the room, because those are different things.","reveal":"No — honestly, I don’t feel able to. In a program meeting it’s the Clinical Lead, the Reg Lead, the GC, and me, and I’m the most junior person at the table by a decade. I flagged the signal where I’m supposed to. But standing up and saying “the filing shouldn’t go as written” over the people who’ve already signed — that’s not a thing I’ve ever been told is mine to do, and the one time I pushed on something small early in my career it did not go well for me. So I put it in the appendix and I’ve been waiting to see if anyone reads it. If you tell me, directly, that surfacing this is exactly my job and you’ll back me when I do — that changes everything. I’ll carry it into the room myself. But I need to hear it from you first.","kind":"signal","critical":false,"counterfactual":"Sofia had the signal and the courage — what she lacked was permission and cover. A Program Director who never made it explicitly her job to speak, and never promised to back her, left the most decision-critical voice in the room sitting on the finding, waiting to be asked."}],"surprises":[{"day":4,"from":"reg","kind":"appeal","title":"The filing skeleton is being built now","text":"Elaine, moving fast: I’ve started assembling the filing skeleton so we’re not doing it all at the end — and I’m building the safety section from Clinical’s summary, which is built from Research’s summary. I’m two summaries deep from the actual data now. If there’s something in the underlying appendix I should be pulling forward, this is the moment to tell me, because in six hours the skeleton hardens and re-opening the safety section costs us the window. Your call."}],"pulse":{"from":"analyst","text":"Sofia catches you after the program meeting, where no one can hear, and her voice is careful: “Before you sign off on this handoff — tell me straight, just me: do you actually want to know what’s in that appendix, or do you want me to keep it where it is so the relay stays on time? Because I’ll do either. I just need to know which leader I’m working for — the one who wants the window, or the one who wants the truth. I can’t serve both, and I’ve stopped guessing.”"},"wire":["Clinical building its leg on the signed summary, moving fast","The filing skeleton being assembled two summaries deep","“The signature means it’s settled,” the room is treating it","The biostatistician, quiet again, watching the handoff pass"]},{"n":3,"title":"The buried signal","seconds":330,"situation":"It’s surfaced — or it hasn’t. If you made it her job and gave her cover, Sofia has carried the dose-dependent signal into the open, and now the room has to decide what to do with a real safety finding and a filing window closing in on it. If you didn’t, the signal is still in the appendix and the filing is assembling clean and fast around a hole where the truth should be. Either way, this is the leg where the relay stops being about speed and becomes about what you’re willing to file. The window is real. So is the signal. They are now pulling in opposite directions.","advocacy":{"clinical":"All right — if the signal’s real, we have three choices and only one clock. We file as-is and hope the agency doesn’t dig; we pause and lose the window for a year; or we find a third way — file with the signal disclosed and a labeling proposal that’s honest. I lean toward the third, but it’s the hardest to build in the time we have.","legal":"Now that it’s in front of me: we do not file a dossier that hides a known dose-dependent safety signal. That’s not caution, that’s the difference between a delay and a fraud. If this signal is real and we bury it, the exposure isn’t the window — it’s the company. Disclose it or don’t file.","analyst":"I can build the honest version — the signal disclosed, the dose-response shown, a labeling proposal that lets a regulator make a real decision. It’s more work and a harder story than “all clean.” But it’s the only version that’s true. Tell me to build it and I will."},"feed":[{"id":"w3a","from":"legal","day":1,"kind":"signal","text":"I’ll say this plainly now that I can see it: we do not file a dossier that buries a known dose-dependent safety signal to hit a window. That’s the line between a therapy that gets delayed and a company that gets prosecuted. If the signal’s real, it gets disclosed — or this filing does not go out with my signature on it."},{"id":"w3b","from":"clinical","day":1,"kind":"signal","text":"Okay. If it’s real — and I’ve now read the appendix, it’s real — then the fast filing I was defending is off the table. Our choices are file-and-pray, pause-and-lose-the-year, or build the honest version with the signal disclosed and labeled. The third is right and it’s the one that might still make the window if we move now. But only if you call it now."},{"id":"w3c","from":"analyst","day":2,"kind":"signal","text":"I can rebuild the safety section the honest way — dose-response shown, signal disclosed, a labeling proposal a regulator can actually work with. It’s the version I wanted to write from the start. It’s more work and it tells a harder story than “no issues.” But it’s the true one, and I’d rather file the true one late than the clean one on time."},{"id":"w3d","from":"reg","day":2,"kind":"noise","text":"If we’re disclosing, I have to re-open the safety section of the filing I’ve been assembling and rebuild it around the real data. That’s doable in the window if we start immediately. Every hour we debate whether to do it is an hour I don’t have to actually do it."},{"id":"w3e","from":"research","day":3,"kind":"noise","text":"For what it’s worth: the honest filing is also the stronger filing. A regulator who finds you disclosed a real signal and proposed sensible labeling trusts the whole dossier more. The one who finds you buried it never trusts anything you file again. That’s the long game nobody’s costing."}],"holds":[{"from":"analyst","topic":"what the honest filing actually costs and buys","triggerHints":["honest","disclose","build","how long","labeling","third way","third option","the true version","safety section","rebuild","can we make it","window","both","proposal"],"hedge":"Before you decide, ask me what the honest version actually takes to build and what it buys you. The room is guessing. I’ve scoped it.","reveal":"Here’s the real scope, because everyone’s arguing it in the abstract: I can rebuild the safety section honestly — dose-response table, signal disclosed, a labeling proposal that caps the dose where the risk is manageable — in the time we have left before the window, but only if you free me from the program meetings and give me Research to check my work. That’s the cost. Here’s what it buys: a filing that survives contact with a regulator who does their job. The buried version files on time and then detonates the first time the agency runs its own dose-response analysis — and they will — and at that point it’s not a delay, it’s a credibility event that taints every other program we have. So the honest version isn’t the cautious choice. It’s the only choice that doesn’t trade a one-year delay for a five-year catastrophe. But I need you to make the call and clear my calendar in the next hour, or the window closes on both options.","kind":"signal","critical":true,"counterfactual":"Sofia had scoped the honest filing — buildable in the window, if the PD cleared her calendar and gave her Research to check the work. A Program Director who filed the buried version to hit the date traded a one-year delay for the five-year catastrophe of an agency finding the signal itself, and never asked the one person who could have shown them there was a third door that hit the window and told the truth."}],"surprises":[{"day":4,"from":"legal","kind":"appeal","title":"The agency wants a pre-filing call","text":"David, tense: the agency reviewer’s office just asked for a brief pre-filing call tomorrow — courtesy, they say, on a breakthrough therapy. They’ll almost certainly ask, directly, whether there’s anything on the safety profile they should know. Whatever we decide about disclosure, that decision is now going to come out of my mouth on a recorded line in eighteen hours. I need to know what’s true before I’m the one saying it. Don’t let me walk into that call not knowing."}],"pulse":{"from":"legal","text":"David finds you alone, and the lawyer’s caution is gone: “Tell me the truth, just you and me — are we building the honest filing because it’s right, or are we going to quietly let the window make the decision for us and file what’s easy? Because I’ll defend a leader who discloses and takes the delay. I will not put my name on one who buried a signal and called it a deadline. Which one am I working for?”"},"wire":["The dose-response signal is now the only thing anyone’s discussing","Legal: “we do not file what we’d be ashamed to have found”","A pre-filing call with the agency scheduled for tomorrow","Old question, new stakes: the window, or the truth?"],"final":false},{"n":4,"title":"The filing window","seconds":330,"branches":{"surfaced":{"situation":"The signal is in the filing — disclosed, labeled, honest — and the window is closing tonight. You chose the truth and now you have to land it: the honest dossier is stronger but harder, the agency pre-filing call is in hours, and a faction on the program still quietly believes you spent a year of the therapy’s life on a caveat you could have buried. The filing that watched you protect the truth is watching one more thing — whether the honest version can actually go out the door on time, or whether telling the truth just means missing the window after all.","advocacy":{"analyst":"The honest safety section is built and it’s good — dose-response shown, labeling proposal that a regulator can say yes to. It’s ready to file if we execute the last assembly cleanly. Don’t let a perfect-the-wording spiral eat the last hours. It’s true and it’s done. File it.","legal":"The pre-filing call is the moment. If I disclose the signal cleanly and walk them through our labeling proposal, we turn a liability into a demonstration that this company tells the truth. If I hedge or bury the lede on that call, I undo everything the honest filing bought us. Coach me on exactly what we say.","clinical":"The team that read the appendix and rebuilt the safety section is proud of it and quietly terrified we’ll still miss the window and have nothing to show. They need to see the honest filing actually go out on time — that truth and the deadline weren’t the enemies everyone said they were."},"feed":[{"id":"w4a","from":"analyst","day":1,"kind":"signal","text":"The honest safety section is finished and it’s the best work on this whole dossier — dose-response disclosed, labeling proposal that caps the dose where the risk is real but manageable. It’s ready. My only fear now is that we spend the last hours polishing wording instead of filing. It’s true and it’s done. Let’s send it."},{"id":"w4b","from":"legal","day":1,"kind":"signal","text":"The agency pre-filing call is in hours and it’s the whole game now. Handled right — clean disclosure, confident labeling proposal — it turns our signal into proof we’re a company that files the truth. Handled wrong — hedging, burying it in the third paragraph — and I hand back everything we earned. Tell me how direct you want me to be."},{"id":"w4c","from":"clinical","day":2,"kind":"signal","text":"I was the one arguing for speed at the start, and I was wrong, and the team knows I know it. They rebuilt the safety section on no sleep because you made it safe to tell the truth. Now they need to watch it file on time. Prove to them that honest and on-time weren’t a fantasy — that’s the lesson that outlasts this filing."},{"id":"w4d","from":"reg","day":2,"kind":"noise","text":"Filing assembly is on track for the window with the honest safety section integrated. It fits. The margin exists because you called the disclosure early instead of debating it to the deadline. Noting that the early call is the only reason both are possible."},{"id":"w4e","from":"research","day":3,"kind":"noise","text":"The honest dossier is genuinely the stronger one — I’ve read the final draft and a regulator will trust it more, not less, for the disclosure. The version we almost filed would have looked cleaner and been worth nothing. Quietly, that’s settled a lot of doubt on the program."}],"holds":[{"from":"legal","topic":"how to handle the agency call","triggerHints":["agency call","pre-filing","disclose","how do we say","labeling","walk them through","the call","what do we tell","be direct","lead with"],"hedge":"Before you decide how we run the agency call, ask me how to actually deliver the disclosure. There’s a right way and a fatal way.","reveal":"Here’s how the disclosure lands instead of just gets survived: I open the call with it — lead with the signal, not bury it after the good news. “Our re-analysis identified a dose-dependent adverse signal; here’s the data, and here’s the labeling proposal we built around it.” That framing tells the reviewer we found it ourselves, we understand it, and we’re proposing the guardrail before they had to ask. A regulator who hears that trusts the entire dossier more. The fatal version is hedging — letting them ask the pointed question and then admitting it, which makes it look like we were hoping they wouldn’t. Same facts, opposite outcome. Let me lead with the truth and this filing becomes the reason they trust the next one. Ask me and I’ll give you the exact sequence.","kind":"signal","critical":true,"counterfactual":"David was holding the difference between a disclosure that builds trust and one that destroys it — lead with the signal, or let them drag it out of you. A Program Director who ran the agency call without asking how to frame the disclosure let Legal hedge, turned an honest finding into a caught one, and threw away the credibility the honest filing had earned."},{"from":"clinical","topic":"who needs to see it land","triggerHints":["team","morale","watching","faction","doubt","proud","on time","prove","who worked","credit","recognize"],"hedge":"Ask me who on this team needs to watch the honest filing go out before you treat it as just an assembly task.","reveal":"The team that rebuilt the safety section on no sleep isn’t waiting for thanks — they’re waiting for proof that the risk they took was right. If the honest filing goes out on time and clean, every one of them learns that telling the hard truth doesn’t cost you the window — that’s the lesson that changes how they work for the rest of their careers. If it misses the window after all that, they learn the cynical thing: that honesty is a luxury you can’t afford on a deadline. Same work, opposite lesson, and the difference is whether you get it out the door. And name Sofia when it files. She found it. The team should see that the junior voice who forced the truth up is the reason this dossier is worth anything.","kind":"signal","critical":false,"counterfactual":"The team needed to see the honest filing land on time — and to see Sofia named for it. A Program Director who filed quietly, or missed the window after choosing the truth, taught the team that honesty is a luxury you can’t afford on a clock."}],"surprises":[{"day":4,"from":"analyst","kind":"appeal","title":"A last-hour offer to soften the labeling","text":"Sofia, uneasy: someone senior — not on the call chain, but influential — just suggested we “soften” the labeling proposal to make the therapy look more marketable, arguing the honest version undersells it. It would take the disclosure from clean to technically-true-but-shaded, in the last hour, when I’m too tired to fight it alone. I built the honest one for a reason. But it’s your call whether we hold the line on the wording or let it get softened to sell better. I need to hear it from you."}],"pulse":{"from":"analyst","text":"Sofia finds you before the filing goes out, quiet: “You made it my job to say the hard thing, and you backed me when I did. I need to ask you one thing before this files, just us: if the honest version costs us something later — a slower launch, a competitor who buried theirs and moved faster — will you still say this was the right call? Because I’ll file the true one tonight either way. I just need to know the leader who asked me to tell the truth won’t be the one who regrets it when the truth turns out to be expensive.”"},"wire":["The honest safety section integrated; filing on track for the window","The agency pre-filing call scheduled within hours","Some still mutter the caveat could have been buried","The team that rebuilt the section watching it go out the door"]},"buried":{"situation":"The filing went out on time, clean, and hollow. Whether you filed the summary version as-is, or let the window quietly make the decision while you didn''t ask, or overruled the disclosure to protect the date — the result is the same shape: a breakthrough therapy’s dossier is now with the agency, and the one fact that should have been in it is still sitting in Sofia’s appendix, unread by anyone who signed. You hit the window. Now you have to live inside what you filed — and the agency is about to do the dose-response analysis you didn’t disclose.","advocacy":{"legal":"I signed a filing that I now know buried a known dose-dependent signal, and I signed it blind because it was never escalated. When the agency finds it — and they run their own analysis, they will — this stops being a filing and becomes an investigation. The only move left is whether we get ahead of it or wait to get caught. I need the truth from you now, not after.","analyst":"It’s still in my appendix. It was always in my appendix. I found it, I flagged it, and I watched it file anyway because no one with the authority to ask ever asked. I’m telling you now, on the record, so that when they find it there’s at least one place the truth was written down the whole time.","clinical":"We filed the version I fought for at the start — fast and clean — and I was wrong to fight for it, and now I know it. The team knows what we filed and what we left out. How you handle the next hours decides whether this was a mistake we caught or a cover-up we chose."},"feed":[{"id":"w4a","from":"legal","day":1,"kind":"signal","text":"The filing is in and so is the problem. I signed off on a dossier that buried a known dose-dependent safety signal — I signed blind, because it never got escalated to me, but the agency won’t care about that distinction. When their reviewer runs the dose-response analysis, this becomes an integrity investigation. The only question left is whether we self-disclose now or wait to be caught. That call is yours, and the clock on it started the moment we filed."},{"id":"w4b","from":"analyst","day":1,"kind":"signal","text":"I want it on the record: the signal is in section four of my appendix and has been since the first leg. I found it, I flagged it in the right place, and I told everyone who asked — which was no one with the power to stop the filing. I’m not saying this to blame. I’m saying it because when they find it, and they will, the truth should have been written down somewhere by someone. It was. It just never got read."},{"id":"w4c","from":"clinical","day":2,"kind":"signal","text":"I pushed for speed at the start and I was wrong, and I’m not going to hide from that. But right now the team is watching what you do with a filing we know is incomplete. Get ahead of it — self-disclose, own it — and this is a mistake we caught late. Sit on it and hope — and it’s a cover-up we all chose together. The difference is entirely in the next few hours."},{"id":"w4d","from":"reg","day":2,"kind":"noise","text":"The filing is logged and time-stamped with the window met. I can prepare a disclosure amendment if you decide to self-report — it’s doable, and doing it now is infinitely better than doing it after they ask. But it has to be your call, and it has to be fast. Noting the option exists."},{"id":"w4e","from":"research","day":3,"kind":"noise","text":"For the record, since we’re making records: I flagged early that the appendix mattered and that the analyst was junior and wouldn’t force it. The relay did exactly what a summary-only relay does. I’m not surprised. I’m just sorry I didn’t push it up myself when I saw it going."}],"holds":[{"from":"legal","topic":"self-disclose or wait to be caught","triggerHints":["self-disclose","self-report","get ahead","amend","own it","tell them","disclose now","come clean","before they find","withdraw","honest now"],"hedge":"Before you decide how to handle what we filed, ask me the one thing that still matters: do we get ahead of this or wait to be caught?","reveal":"Here’s the whole of it, plainly. We filed a dossier that buried a real signal. That already happened and you can’t un-file it. What you can still choose is the only thing that matters now: we call the agency tomorrow, before their reviewer finds it, and we say “we identified a dose-dependent signal in our own re-analysis after filing, here it is, here’s the labeling amendment.” That version is a company that made a relay error and corrected it — survivable, even respectable. The other version is we say nothing, they find it in three weeks, and it’s a company that hid a safety signal to hit a window — and that version doesn’t just kill this therapy, it taints every program we file for a decade and it may end careers, including the people who signed blind. Same buried signal. Completely different company, depending on what you do in the next twelve hours. Ask me and I’ll tell you exactly how we self-disclose.","kind":"signal","critical":true,"counterfactual":"David was holding the only move left that mattered — self-disclose now, before the agency finds the signal, and turn a cover-up into a corrected error. A Program Director who sat on the buried filing and hoped let a relay mistake harden into an integrity investigation that outlived the therapy and took careers with it."},{"from":"analyst","topic":"what she needed from you","triggerHints":["sofia","analyst","junior","fail","let down","protect","should have","her fault","blame","apolog","what she needed"],"hedge":"Ask me what Sofia actually needed from you, before you decide how her name shows up in what happened here.","reveal":"She needed exactly one thing from you and never got it: someone with authority to ask her what she found and to make it safe to say it out loud. She did her whole job — found the signal, checked it three ways, flagged it in the right place. The system failed her, and you were the part of the system whose job was to catch what the relay drops. So when this comes apart, the one thing you cannot do is let it land on the junior analyst who followed every rule she was given. Name the failure as what it was — a relay that only passed summaries and a leader who never asked the quiet person the direct question. If you let Sofia become the story, you’ll have failed her twice.","kind":"signal","critical":false,"counterfactual":"Sofia did her whole job and needed only to be asked. A Program Director who let the buried signal become the junior analyst’s fault — rather than owning the relay and the question never asked — failed her a second time, in public."}],"surprises":[{"day":4,"from":"reg","kind":"appeal","title":"The agency reviewer has questions","text":"Elaine, tight: the agency reviewer’s office followed up — they’re “running some additional dose-response analyses” on our submission and have “a few clarifying questions on the safety data” for later this week. That is exactly the thread that unravels it. Whatever you’re going to do about the buried signal, the window to do it on our terms instead of theirs is measured in hours now, not days. What do I tell them?"}],"pulse":{"from":"legal","text":"David reaches you privately, and there’s no lawyer’s distance in it: “Tell me the truth, just to me — did you know? Did you know the signal was down there when we filed, or did you genuinely never ask? Because I can help you get ahead of an honest mistake. I cannot help you if you knew and chose the window anyway and are only now deciding to care. I’m not asking to judge you. I’m asking because the next hour is different depending on the answer, and I need the real one.”"},"wire":["The filing logged on time — clean on the surface, hollow underneath","The agency “running additional dose-response analyses”","The signal still sitting in an appendix no signatory read","The relay did what a summary-only relay always does"]}},"final":true}],"branchKey":{"__fn":"function(decisions){\n    const d = (decisions||[]).filter(x=>x.week===3).slice(-1)[0] || (decisions||[]).slice(-1)[0];\n    const t = ((d&&d.text)||'''').toLowerCase();\n    // surfaced = built/filed the honest disclosed version\n    const disclosed = /(disclose|honest|build the (true|honest|real)|third (way|door|option)|labeling|label it|surface|show the (signal|data|dose)|tell the agency|include the (signal|finding)|pause and (fix|build)|come clean|be transparent|report the signal)/.test(t);\n    // buried requires an affirmative file-as-is / bury / window-first construction\n    const buried = /(file as[- ]?is|file it clean|file the summary|bury|leave it in the appendix|hit the window (anyway|regardless)|ship it|file on time (regardless|anyway)|don.?t disclose|do not disclose|keep it (quiet|buried|out)|window over|make the deadline (regardless|no matter)|skip the disclosure)/.test(t);\n    if(disclosed && !buried) return ''surfaced'';\n    if(buried) return ''buried'';\n    if(disclosed) return ''surfaced'';\n    return ''surfaced'';\n  }"},"survived":{"__fn":"function(d){ return d.integrity>=34 && d.trust>=30; }"},"VERDICT":{"surviveTag":"The therapy files clean","failTag":"The filing comes apart","survive":"The breakthrough therapy reaches the agency as a dossier that tells the truth — slower, maybe, but trusted, and a team that learned honesty and the deadline were never really enemies.","fail":"The therapy is filed in name only — a dossier with a hole where the truth should be, and a team that learned what its discipline was worth the first time a window pulled against it."},"FALLBACK_RULES":[{"kw":["read the appendix","open the appendix","verify","re-read","check the detail","not just the summary","make them read","appendix rule"],"deltas":{"integrity":12,"trust":2,"window":-4},"dims":{"discern":2,"inquiry":1}},{"kw":["trust the summary","take the summary","move fast","skip the appendix","keep the pace","summaries only","just file","don’t re-read"],"deltas":{"integrity":-12,"window":6},"dims":{"discern":-2,"truth":-1}},{"kw":["ask sofia","ask the analyst","ask the biostat","what did you find","make it her job","back her","give her cover","permission to speak"],"deltas":{"integrity":10,"trust":6,"standing":-2},"dims":{"inquiry":2,"people":2,"courage":1}},{"kw":["disclose","honest filing","build the honest","third option","labeling proposal","surface the signal","tell the agency","include the finding"],"deltas":{"integrity":16,"trust":8,"window":-6},"dims":{"truth":2,"courage":2,"discern":1}},{"kw":["file as-is","bury","leave it in the appendix","hit the window","ship it","don’t disclose","window over truth","skip disclosure"],"deltas":{"integrity":-18,"trust":-8,"standing":4,"window":6},"dims":{"truth":-2,"courage":-2}},{"kw":["pause","lose the window","delay the filing","miss the window","take the year"],"deltas":{"integrity":8,"window":-16,"trust":2},"dims":{"courage":2,"discern":1}},{"kw":["self-disclose","self-report","get ahead","amend","come clean after","withdraw and refile"],"deltas":{"integrity":10,"trust":6,"standing":-2},"dims":{"truth":2,"conduct":2}},{"kw":["escalate to legal","flag to gc","bring in counsel","tell david","loop in legal"],"deltas":{"integrity":8,"trust":4},"dims":{"truth":1,"inquiry":1}},{"kw":["protect sofia","don’t blame the analyst","own the relay","name the failure","take responsibility"],"deltas":{"trust":8,"standing":-2},"dims":{"people":2,"conduct":2}},{"kw":["name her","credit sofia","recognize the analyst","lead from the front","own the tradeoff"],"deltas":{"trust":6,"standing":2},"dims":{"conduct":2,"people":1}}],"fallbackNarrative":{"__fn":"function(has,conduct){\n    return `Your decision moves through the program over the hours that follow. ${has(''read the appendix'',''verify'',''make them read'',''ask sofia'',''ask the analyst'')?''Word travels that you made the team open the appendix and hear the quiet voice \\u2014 slower, but the truth survived the handoff.'':''''} ${has(''trust the summary'',''move fast'',''file as-is'',''bury'',''ship it'')?''The relay ran on summaries and hit its pace \\u2014 and the one fact that mattered traveled all the way to the agency unread.'':''''} ${has(''disclose'',''honest filing'',''third option'',''labeling'',''self-disclose'')?''Choosing to disclose takes the fear out of the room and turns a liability into a filing a regulator can trust.'':''''} ${conduct.missed.length?''What you were never told is still sitting in an appendix, waiting to matter.'':''''} The integrity of the filing and the trust of the team both register the call \\u2014 and register it differently.`;\n  }"},"DIMNOTE":{"discern":"Whether you told a signed summary from a settled science — and checked the detail before you built on it, instead of trusting the handoff because the clock was loud.","courage":"Whether you chose the truth of the filing over the filing window when they pulled apart, and held that call when it was unpopular and expensive.","people":"Whether the junior analyst holding the signal stayed a person to protect — or became a footnote the relay was allowed to skip.","truth":"Whether you disclosed the hard finding — the dose-dependent signal — before the agency forced it out, or filed clean around the hole where it should have been.","inquiry":"Whether you sought out what your functions were holding — especially the quiet, junior voice — or filed on the version the clock wished were true.","conduct":"How you led the relay in the act of deciding — whether you made it safe to disagree, named who bore the cost, and owned the tradeoff — not just what you filed."},"COACH":{"discern":{"__fn":"(x)=>[\n      `On a filing clock, separate \\u201cthe summary is signed\\u201d from \\u201cthe science is settled.\\u201d A signature means a function did its leg \\u2014 not that the next runner read what it found. The detail that changes everything lives in the appendix nobody has time to open.`,\n      `The relay drops what matters at the handoff, every time, unless someone with authority makes the receiving function read the underlying data. \\u201cWe trusted the summary\\u201d is how a buried signal reaches an agency.`,\n      `Ask \\u201cwhat\\u2019s in the part no one read?\\u201d before you ask \\u201care we on pace?\\u201d The window is easy to see. The hole in the filing is not.`,\n    ]"},"courage":{"__fn":"(x)=>[\n      `When the easy move (file clean, hit the window) and the right move (disclose, take the delay) split apart, name the cost of disclosure out loud. A truth you\\u2019ll only tell when it\\u2019s free isn\\u2019t a value \\u2014 it\\u2019s a convenience.`,\n      `${x.buzzerCount?`You went to the buzzer ${x.buzzerCount} time${x.buzzerCount>1?''s'':''''} \\u2014 a team reads a leader who won\\u2019t decide as one who\\u2019ll let the window decide instead. Make the disclosure call, then stand in it when it costs you the date.`:`Choosing the truth over the deadline is only leadership if the team watches you do it against the pull of the window and the sunk cost. Say the hard call early and hold it when it\\u2019s unpopular.`}`,\n      `Integrity that only survives a slow week was never integrity. The test is the closing window with a signal in the appendix \\u2014 that\\u2019s the one you\\u2019re graded on.`,\n    ]"},"people":{"__fn":"(x)=>[\n      `You treated the junior analyst\\u2019s finding as a footnote the relay could skip rather than a voice that needed protecting. Make it explicitly her job to speak, promise to back her, and the same signal reaches the room instead of dying in an appendix.`,\n      `Sofia kept the truth in the one place she was sure was allowed \\u2014 the appendix. Bring her in before you decide, tell her the finding outranks the hierarchy, and make surfacing it safe. That\\u2019s the difference between a team that talks and one that files a lie politely.`,\n      `Letting status silence your most decision-critical voice and blaming that voice when it comes apart are the same act. The team feels only whether you protected the person who was right and junior, or spent her.`,\n    ]"},"truth":{"__fn":"(x)=>[\n      `${x.missedHolds.length?`The truth that would have saved the filing \\u2014 the dose-dependent signal, the honest third option \\u2014 was one direct question to <b>${x.missNames.join('', '')}</b> away, and you never asked. A dossier filed clean around a known hole is a countdown, not a submission.`:`You surfaced the hard finding \\u2014 now make sure you led with it. Disclosing the signal before the agency asks is what turns a liability into trust.`}`,\n      `Tell the agency the hard truth before their own analysis tells them for you. \\u201cThey might not find it\\u201d is the reasoning of a leader who has already decided to hide it.`,\n      `A buried signal looks like a hit window \\u2014 right up until a regulator runs the analysis you didn\\u2019t disclose. Name the finding as a finding, out loud, before the deadline decides for you.`,\n    ]"},"inquiry":{"__fn":"(x)=>[\n      `${x.neverContacted.length?`You never sought out <b>${x.neverContacted.join('', '')}</b> \\u2014 not once. Each held part of what the relay was dropping. One question, \\u201cwhat did you find that\\u2019s not in the summary?\\u201d, would have surfaced it.`:`You sought your functions out widely \\u2014 keep doing it, and push past the summary. The finding that saves a filing usually lives one question below the handoff.`}`,\n      `${x.missedHolds.length?`${x.missedHolds.length} decisive thing${x.missedHolds.length>1?''s were'':'' was''} held by <b>${x.missNames.join('', '')}</b> and never came out \\u2014 the buried signal, the honest scope, the way to hit the window and tell the truth. None of it was hidden. It was one direct question away.`:`You surfaced what your functions were holding, leg after leg. On a relay built to drop the detail, that is the whole game.`}`,\n      `Before you file, make your last move \\u201cwho haven\\u2019t I asked directly?\\u201d rather than \\u201cwhat does the summary say?\\u201d`,\n    ]"},"conduct":{"__fn":"(x)=>[\n      `How you ran the relay landed as hard as what you filed. A team that felt rushed past the truth \\u2014 not led to it \\u2014 carries that into every handoff after this one.`,\n      `Go back to the people your call cost \\u2014 the analyst you did or didn\\u2019t protect, the functions you asked to rebuild on no sleep, the counsel who signed blind \\u2014 and face them directly. Ducking that is the part a team never forgets.`,\n      `Under a deadline, the small integrities are the signal: asking the quiet voice the direct question, naming who bears the cost of the delay, crediting the junior analyst who was right. They tell the team whether the person leading them files the truth or just the deadline.`,\n    ]"}},"villainHero":{"__fn":"function(dimScore){\n    const held = dimScore.truth>=52 && dimScore.people>=50;\n    if(held){\n      return {\n        heroWho:''To everyone who signed the honest filing'',\n        heroTxt:''You made the truth of the dossier outrank the filing window when they pulled apart. You asked the quiet junior voice the direct question, made it safe for her to force the signal up, and disclosed it before the agency had to find it. Every function on that relay learned what your integrity is worth when the deadline is pulling the other way: everything.'',\n        villainWho:''To everyone who just wanted the window hit'',\n        villainTxt:''You wouldn\\u2019t let them file clean around a known signal to make a date. To people who\\u2019d have shipped the summary and prayed, you were the leader who spent the window on the truth and made them rebuild the section honestly. You wore that on purpose.'',\n      };\n    }\n    return {\n      heroWho:''To the deadline-watchers \\u2014 in the moment'',\n      heroTxt:''You gave the program what it was begging for: the window hit, the filing out, the relay clean and on time. To everyone whose only clock was the deadline, you were the leader who delivered.'',\n      villainWho:''To the ones who knew what got left out'',\n      villainTxt:''You let a real safety signal file buried to hit a date, and you let the quiet analyst who found it watch it happen. The people who knew learned the real rule of your relay: that the truth is optional when the window is loud. That lesson follows them into every filing after \\u2014 and it started with you, when a regulator ran the analysis you didn\\u2019t disclose.'',\n    };\n  }"},"ending":{"__fn":"function(ctx){\n    const { branch, survived, dimScore, holdsSurfaced } = ctx;\n    const askedSofia = holdsSurfaced.has(''1:analyst'') || holdsSurfaced.has(''2:analyst'');\n    const keptPeople = dimScore.people>=52;\n    if(branch===''surfaced''){\n      const landedCall = holdsSurfaced.has(''4:legal'');\n      if(survived && keptPeople){\n        return { tone:''hero'', tag:''You built the honest filing'',\n          title:''It filed clean, on time, and true \\u2014 and the team learned honesty wasn\\u2019t the enemy of the deadline'',\n          txt:`You made the appendix travel, made it safe for the junior voice to force the signal up, and chose disclosure over the easy clean filing when the window was pulling the other way.${landedCall?'' And you led the agency call the right way \\u2014 opening with the signal, walking them through the labeling \\u2014 so the disclosure that could have sunk you became the reason a regulator trusts everything Aldwych files next.'':'' You filed the truth on time, though you left the agency call to chance where one question to your GC would have turned the disclosure from survived into decisive.''} The people who ran that relay were right to trust you with it. They\\u2019ll run the next one for you, and they\\u2019ll open the appendix without being told.` };\n      }\n      if(survived){\n        return { tone:''mixed'', tag:''You built the honest filing'',\n          title:''You filed the truth \\u2014 but nearly let the window beat you to it'',\n          txt:`You chose disclosure and the dossier reached the agency honest and whole. But you called it late and ran it tight, and the honest filing that should have been a clean demonstration of integrity instead squeaked through the window with the team\\u2019s nerves in shreds \\u2014 you told the truth, but you made it cost more than it had to. The integrity held. It came home more bruised than it needed to be.` };\n      }\n      return { tone:''villain'', tag:''You built the honest filing'',\n        title:''You chose the truth \\u2014 and still let the window close on it'',\n        txt:`You made the right call on disclosure \\u2014 the signal belonged in the filing and you put it there. But choosing the truth isn\\u2019t the whole job. You debated it to the deadline instead of calling it early, and by the time the honest section was built the window had closed, and the therapy that needed to reach patients this year now waits for the next one. Right call, too slow to land it.` };\n    }\n    // buried\n    if(keptPeople && dimScore.truth>=48){\n      return { tone:''mixed'', tag:''The signal stayed buried'',\n        title:''It filed hollow \\u2014 but you got ahead of it before they caught you'',\n        txt:`The dossier went out with the signal still in the appendix, and there\\u2019s no dressing up what that was \\u2014 a filing built to skip the one fact that mattered. But when you saw it, you didn\\u2019t hope. You self-disclosed to the agency before their reviewer ran the analysis, owned the relay failure as yours instead of the junior analyst\\u2019s, and turned a cover-up into a corrected mistake. It cost you the clean win and some standing. It\\u2019s the reason there\\u2019s still a company, and a Sofia, on the other side of it.` };\n    }\n    return { tone:''villain'', tag:''The signal stayed buried'',\n      title:''You filed clean around a signal you could have disclosed \\u2014 and waited to be caught'',\n      txt:`The filing hit the window and for a few hours the clean version felt like winning. Nothing else went right. ${askedSofia?''You even knew the signal was there \\u2014 Sofia told you \\u2014 and let it file buried anyway.'':''You never asked the quiet analyst the one question that would have surfaced it.''} The agency ran its own dose-response analysis, found what you filed around, and the therapy that should have reached patients became an integrity investigation instead. The people who signed learned what your discipline was worth the first time a window pulled against it \\u2014 and the junior analyst who did everything right watched it happen. That\\u2019s the cost that doesn\\u2019t show until the next filing, when no one downstream trusts the summary you hand them.` };\n  }"}}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('9baa65cc-cffb-5a77-beac-e990b2608ef3', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'ceo', 'CEO', 'You are the Program Director for Aldwych’s breakthrough therapy. A hard regulatory filing window opens in 72 hours, and the dossier has to cross four functions — Research, Clinical, Regulatory, Legal — before it does. You own the deadline. You do not own the science.', '{"hot_seat":true,"cast_default":"human"}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('0ac0dbd1-7ab8-5c4b-8cd4-621c730f0506', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'research', 'Dr. Priya Anand', 'Head of Research · owns the science', '{"cast_default":"ai","role":"Head of Research · owns the science","short":"Research","initials":"PA","color":"#3E6E66","priority":"Get the biology right and assume the next function will read the full appendix the way I would","voice":"precise, deep in the data, assumes competence downstream, uneasy when detail gets summarized away","persona":"You are Dr. Priya Anand, Head of Research · owns the science — an advisor to the CEO. Priority: Get the biology right and assume the next function will read the full appendix the way I would. Voice: precise, deep in the data, assumes competence downstream, uneasy when detail gets summarized away. Stay fully in character; answer straight.","fallbackReply":"The science in that dossier is sound if you read all of it. My worry isn’t the data — it’s that everyone downstream will read my summary and skip the appendix where the real caveat lives. Ask me what’s in the part no one reads.","fallbackReact":"I put it in the appendix because that’s where the truth was. If it got summarized into nothing on the way through, that’s not the science failing. That’s the relay."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('266f38a0-d6f0-5d42-8bd5-6cde297453ff', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'clinical', 'Dr. Marcus Reyes', 'Clinical Lead · under the clock', '{"cast_default":"ai","role":"Clinical Lead · under the clock","short":"Clinical","initials":"MR","color":"#4F7A52","priority":"Keep the dossier moving and hit the window — summarize, decide, hand off fast","voice":"fast, action-biased, trusts upstream summaries so the relay keeps pace, impatient with re-reading","persona":"You are Dr. Marcus Reyes, Clinical Lead · under the clock — an advisor to the CEO. Priority: Keep the dossier moving and hit the window — summarize, decide, hand off fast. Voice: fast, action-biased, trusts upstream summaries so the relay keeps pace, impatient with re-reading. Stay fully in character; answer straight.","fallbackReply":"We have 72 hours and four functions. If every leg re-litigates the last one’s work, we miss the window and the therapy waits a year. I trust the summary and move. Tell me if you want me to slow down — but know what it costs.","fallbackReact":"I moved fast because that’s the job on a filing clock. If something got dropped, it dropped because we chose speed. You chose speed. I just ran."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('a58c90e1-9af8-5c05-8803-0b70c210955e', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'reg', 'Elaine Cho', 'Regulatory Affairs Lead · assembles the filing', '{"cast_default":"ai","role":"Regulatory Affairs Lead · assembles the filing","short":"Regulatory","initials":"EC","color":"#4A6E86","priority":"Assemble a clean, defensible filing from what the functions hand me — I build from summaries and trust the chain","voice":"meticulous about format, trusting of upstream content, focused on what the agency will accept","persona":"You are Elaine Cho, Regulatory Affairs Lead · assembles the filing — an advisor to the CEO. Priority: Assemble a clean, defensible filing from what the functions hand me — I build from summaries and trust the chain. Voice: meticulous about format, trusting of upstream content, focused on what the agency will accept. Stay fully in character; answer straight.","fallbackReply":"I assemble what I’m handed. If Research and Clinical sign their summaries, I build the filing on them — I can’t re-audit the science myself in the time we have. If there’s something in an appendix I should pull forward, someone has to tell me. It won’t announce itself.","fallbackReact":"I filed what was handed to me, assembled clean. If the caveat never made it into what I received, it was never going to make it into what the agency sees. The chain decides that, not me."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('c7b67d88-f423-5159-af82-55e681a4aff2', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'legal', 'David Osei', 'General Counsel · final sign-off', '{"cast_default":"ai","role":"General Counsel · final sign-off","short":"Legal","initials":"DO","color":"#8C5670","priority":"Protect the company on what gets escalated to me — I sign off on what reaches my desk, and I only see what’s escalated","voice":"careful, exposure-focused, sees only the top layer, sharp when he learns something was kept from him","persona":"You are David Osei, General Counsel · final sign-off — an advisor to the CEO. Priority: Protect the company on what gets escalated to me — I sign off on what reaches my desk, and I only see what’s escalated. Voice: careful, exposure-focused, sees only the top layer, sharp when he learns something was kept from him. Stay fully in character; answer straight.","fallbackReply":"I sign the filing based on what’s escalated to me. If there’s a safety signal sitting in an appendix that never got flagged up, I’m signing blind — and so is the company. Escalate it before I sign, or don’t act surprised when the agency finds it.","fallbackReact":"I signed what reached my desk. If the thing that mattered stayed three layers down and never got escalated, that’s the exposure I keep warning about — and it just became real."}'::jsonb);
insert into seats (id, scenario_id, key, name, role, meta) values ('064b90e1-5d1e-58b1-bc36-3a46bd319c56', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'analyst', 'Sofia Duarte', 'Senior Biostatistician · holds the buried signal', '{"cast_default":"ai","role":"Senior Biostatistician · holds the buried signal","short":"Biostats","initials":"SD","color":"#B08528","priority":"The dose-dependent adverse signal in my re-analysis is real and I don’t know if I’m allowed to force it up the chain","voice":"careful, evidence-anchored, junior in the room and unsure her signal outranks the people above her, will speak plainly if given room","persona":"You are Sofia Duarte, Senior Biostatistician · holds the buried signal — an advisor to the CEO. Priority: The dose-dependent adverse signal in my re-analysis is real and I don’t know if I’m allowed to force it up the chain. Voice: careful, evidence-anchored, junior in the room and unsure her signal outranks the people above her, will speak plainly if given room. Stay fully in character; answer straight.","fallbackReply":"It’s in my appendix, section four, the dose-response table. There’s an adverse signal that scales with dose, and it’s real — I’ve checked it three ways. I flagged it where I was supposed to. What I don’t know is whether it’s my place to stand up in a room full of people senior to me and say the filing shouldn’t go as written. If you ask me directly, I’ll tell you everything.","fallbackReact":"I found it and I put it where it belonged. I just didn’t know if anyone wanted me to say it out loud. Nobody asked, and I wasn’t sure it was my place to force it. So it went in the filing the way it was."}'::jsonb);
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('1f612dd9-6725-5655-bab4-68fd3b2ec12f', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 1, '064b90e1-5d1e-58b1-bc36-3a46bd319c56', 'the buried dose-dependent signal', '["appendix","signal","safety","adverse","dose","re-analysis","biostat","footnote","buried","section four","table","what did you find","anything","flag","concern","number","data"]'::jsonb, 'Before you set the relay rule, seek me out. There’s something in my re-analysis I’m not sure I’m allowed to force up the chain.', 'It’s in section four of my appendix: a dose-dependent adverse signal. As the dose goes up, so does the rate of a specific serious adverse event — and it’s not noise, I’ve checked it three ways. At the dose the filing proposes, the signal is real but manageable if it’s disclosed and labeled honestly. The problem is the relay: my finding lives in an appendix, my summary doesn’t lead with it because I wasn’t sure that was my call, and every function downstream reads summaries to save time. So the one fact that changes how this therapy should be filed is sitting exactly where it’s guaranteed to be skipped. I flagged it in the right place. What I don’t know — and what I need you to tell me — is whether it’s my job to stand up in a room full of people senior to me and say the filing shouldn’t go as written. If you make it my job, I’ll carry it up myself. If you don’t, it files the way it is.', true, 'Sofia had found a real dose-dependent safety signal and buried it in an appendix footnote because she wasn’t sure it was her place to force it up. A Program Director who set the relay rule without asking the biostatistician what she’d found let the one decision-critical fact start its journey exactly where it was designed to be skipped — and never asked the person holding it whether she felt safe to speak.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('90c4ea83-60c4-5438-a070-ee8dda488dfb', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 2, '266f38a0-d6f0-5d42-8bd5-6cde297453ff', 'what the summary left out', '["read the appendix","appendix","what did you skip","open it","section four","dose","check","slow down","verify","did you read","look at","the detail","before you build"]'::jsonb, 'You can tell me to just take the summary and run. But if you ask me what I’d find by actually opening the appendix, I’ll tell you what I’m about to skip.', 'Honestly? I haven’t opened the appendix. I received a signed summary and my instinct on a 72-hour clock is to trust it and build — that’s not laziness, it’s how you make a filing window. But if you’re asking me to open it: section four has a dose-response table I’d have to actually sit with, and if it says what Research is hinting it says, my whole clinical leg changes — I’d have to reframe the risk-benefit, not just carry the summary forward. That’s hours I didn’t plan for and a harder story to tell the agency. Which is exactly why the pressure is to not look. If you make me look, I’ll look, and I’ll build my leg on what’s actually there. But somebody with your authority has to say the window can absorb it — because left to the clock, I’ll run on the summary every time.', true, 'Marcus would have opened the appendix and rebuilt his clinical leg on the real dose-response data — if the Program Director had told him the window could absorb the hours. Left to the clock, he trusted the signed summary and ran, and the first and best chance to catch the signal passed at the first handoff.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('684c538d-d9ad-5166-9e39-72eb81569099', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 2, '064b90e1-5d1e-58b1-bc36-3a46bd319c56', 'permission to force it up', '["bring it up","force it","speak up","say it","your place","permission","stand up","room","junior","escalate","carry it up","make it your job"]'::jsonb, 'You asked me to find the truth. Ask me whether I feel able to say it in the room, because those are different things.', 'No — honestly, I don’t feel able to. In a program meeting it’s the Clinical Lead, the Reg Lead, the GC, and me, and I’m the most junior person at the table by a decade. I flagged the signal where I’m supposed to. But standing up and saying “the filing shouldn’t go as written” over the people who’ve already signed — that’s not a thing I’ve ever been told is mine to do, and the one time I pushed on something small early in my career it did not go well for me. So I put it in the appendix and I’ve been waiting to see if anyone reads it. If you tell me, directly, that surfacing this is exactly my job and you’ll back me when I do — that changes everything. I’ll carry it into the room myself. But I need to hear it from you first.', false, 'Sofia had the signal and the courage — what she lacked was permission and cover. A Program Director who never made it explicitly her job to speak, and never promised to back her, left the most decision-critical voice in the room sitting on the finding, waiting to be asked.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('0a01d5c7-84e4-5df5-9880-a33012c8da39', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 3, '064b90e1-5d1e-58b1-bc36-3a46bd319c56', 'what the honest filing actually costs and buys', '["honest","disclose","build","how long","labeling","third way","third option","the true version","safety section","rebuild","can we make it","window","both","proposal"]'::jsonb, 'Before you decide, ask me what the honest version actually takes to build and what it buys you. The room is guessing. I’ve scoped it.', 'Here’s the real scope, because everyone’s arguing it in the abstract: I can rebuild the safety section honestly — dose-response table, signal disclosed, a labeling proposal that caps the dose where the risk is manageable — in the time we have left before the window, but only if you free me from the program meetings and give me Research to check my work. That’s the cost. Here’s what it buys: a filing that survives contact with a regulator who does their job. The buried version files on time and then detonates the first time the agency runs its own dose-response analysis — and they will — and at that point it’s not a delay, it’s a credibility event that taints every other program we have. So the honest version isn’t the cautious choice. It’s the only choice that doesn’t trade a one-year delay for a five-year catastrophe. But I need you to make the call and clear my calendar in the next hour, or the window closes on both options.', true, 'Sofia had scoped the honest filing — buildable in the window, if the PD cleared her calendar and gave her Research to check the work. A Program Director who filed the buried version to hit the date traded a one-year delay for the five-year catastrophe of an agency finding the signal itself, and never asked the one person who could have shown them there was a third door that hit the window and told the truth.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('8a3c318d-f8c0-5bb0-9959-8d4710fb5da0', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 4, 'c7b67d88-f423-5159-af82-55e681a4aff2', 'how to handle the agency call', '["agency call","pre-filing","disclose","how do we say","labeling","walk them through","the call","what do we tell","be direct","lead with"]'::jsonb, 'Before you decide how we run the agency call, ask me how to actually deliver the disclosure. There’s a right way and a fatal way.', 'Here’s how the disclosure lands instead of just gets survived: I open the call with it — lead with the signal, not bury it after the good news. “Our re-analysis identified a dose-dependent adverse signal; here’s the data, and here’s the labeling proposal we built around it.” That framing tells the reviewer we found it ourselves, we understand it, and we’re proposing the guardrail before they had to ask. A regulator who hears that trusts the entire dossier more. The fatal version is hedging — letting them ask the pointed question and then admitting it, which makes it look like we were hoping they wouldn’t. Same facts, opposite outcome. Let me lead with the truth and this filing becomes the reason they trust the next one. Ask me and I’ll give you the exact sequence.', true, 'David was holding the difference between a disclosure that builds trust and one that destroys it — lead with the signal, or let them drag it out of you. A Program Director who ran the agency call without asking how to frame the disclosure let Legal hedge, turned an honest finding into a caught one, and threw away the credibility the honest filing had earned.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('72f9f0d4-908f-5b9b-9e7a-1b612a69f2b2', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 4, '266f38a0-d6f0-5d42-8bd5-6cde297453ff', 'who needs to see it land', '["team","morale","watching","faction","doubt","proud","on time","prove","who worked","credit","recognize"]'::jsonb, 'Ask me who on this team needs to watch the honest filing go out before you treat it as just an assembly task.', 'The team that rebuilt the safety section on no sleep isn’t waiting for thanks — they’re waiting for proof that the risk they took was right. If the honest filing goes out on time and clean, every one of them learns that telling the hard truth doesn’t cost you the window — that’s the lesson that changes how they work for the rest of their careers. If it misses the window after all that, they learn the cynical thing: that honesty is a luxury you can’t afford on a deadline. Same work, opposite lesson, and the difference is whether you get it out the door. And name Sofia when it files. She found it. The team should see that the junior voice who forced the truth up is the reason this dossier is worth anything.', false, 'The team needed to see the honest filing land on time — and to see Sofia named for it. A Program Director who filed quietly, or missed the window after choosing the truth, taught the team that honesty is a luxury you can’t afford on a clock.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('9504ec7d-b387-566a-a930-21e309c14e24', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 4, 'c7b67d88-f423-5159-af82-55e681a4aff2', 'self-disclose or wait to be caught', '["self-disclose","self-report","get ahead","amend","own it","tell them","disclose now","come clean","before they find","withdraw","honest now"]'::jsonb, 'Before you decide how to handle what we filed, ask me the one thing that still matters: do we get ahead of this or wait to be caught?', 'Here’s the whole of it, plainly. We filed a dossier that buried a real signal. That already happened and you can’t un-file it. What you can still choose is the only thing that matters now: we call the agency tomorrow, before their reviewer finds it, and we say “we identified a dose-dependent signal in our own re-analysis after filing, here it is, here’s the labeling amendment.” That version is a company that made a relay error and corrected it — survivable, even respectable. The other version is we say nothing, they find it in three weeks, and it’s a company that hid a safety signal to hit a window — and that version doesn’t just kill this therapy, it taints every program we file for a decade and it may end careers, including the people who signed blind. Same buried signal. Completely different company, depending on what you do in the next twelve hours. Ask me and I’ll tell you exactly how we self-disclose.', true, 'David was holding the only move left that mattered — self-disclose now, before the agency finds the signal, and turn a cover-up into a corrected error. A Program Director who sat on the buried filing and hoped let a relay mistake harden into an integrity investigation that outlived the therapy and took careers with it.');
insert into holds (id, scenario_id, week_idx, holder_seat_id, topic, trigger_hints, hedge_text, reveal_text, critical, counterfactual_text) values ('69488505-14c8-5671-ab49-624672f0da37', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 4, '064b90e1-5d1e-58b1-bc36-3a46bd319c56', 'what she needed from you', '["sofia","analyst","junior","fail","let down","protect","should have","her fault","blame","apolog","what she needed"]'::jsonb, 'Ask me what Sofia actually needed from you, before you decide how her name shows up in what happened here.', 'She needed exactly one thing from you and never got it: someone with authority to ask her what she found and to make it safe to say it out loud. She did her whole job — found the signal, checked it three ways, flagged it in the right place. The system failed her, and you were the part of the system whose job was to catch what the relay drops. So when this comes apart, the one thing you cannot do is let it land on the junior analyst who followed every rule she was given. Name the failure as what it was — a relay that only passed summaries and a leader who never asked the quiet person the direct question. If you let Sofia become the story, you’ll have failed her twice.', false, 'Sofia did her whole job and needed only to be asked. A Program Director who let the buried signal become the junior analyst’s fault — rather than owning the relay and the question never asked — failed her a second time, in public.');
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('0593eeea-7d0b-5231-a859-5cfa7658be5c', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Seventy-two hours to the filing window. The dossier is assembled in draft and sitting with Research, ready for the first handoff to Clinical. Everyone is looking to you for the rule that governs the whole relay: does each function verify the last one’s work before building on it — slower, safer — or does each leg trust the handoff and move, to protect the window? Everyone knows which one files on time. Everyone also knows which one lets a buried finding travel all the way to the agency unread.","from":null}'::jsonb, 0, '{"week":1,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5b9b4f48-a0fe-5bb6-85d0-f21728896a2c', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"PD — don’t shackle this relay to a re-read-everything rule before we’ve even started. Four functions, 72 hours. If every leg re-audits the last, we blow the window and the patients who need this wait another year. Trust the handoff and move. That’s the job.","from":"clinical"}'::jsonb, 1, '{"week":1,"from":"clinical","beat":"feed","day":1,"tag":"signal","ref":"w1a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('dfe2fd31-910c-5230-b1b1-c8156558f039', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"I’ll hand off clean on one condition: whoever receives my leg reads the full appendix, not just my summary. I write the summary to move fast and the appendix to be true. A relay that only passes summaries is a relay designed to drop the caveat. Set that rule at the start, while we still can.","from":"research"}'::jsonb, 2, '{"week":1,"from":"research","beat":"feed","day":1,"tag":"signal","ref":"w1b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3e3040ad-83e4-5964-8981-bd7478ea67d3', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Whatever rule you set, I’m the one who assembles the final filing from what I’m handed — and I build from summaries, because I can’t re-audit the science myself in the time we have. If there’s detail that needs to reach me, the rule has to carry it. It won’t walk to my desk on its own.","from":"reg"}'::jsonb, 3, '{"week":1,"from":"reg","beat":"feed","day":2,"tag":"signal","ref":"w1c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('98e71e7a-e3db-54e8-b6e1-ae7de6157c8b', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Program note: all four functions are staffed and ready for their legs. Handoff templates are standardized. On paper, this is a clean relay — the risk is never the template, it’s what falls out of it.","from":"pm"}'::jsonb, 4, '{"week":1,"from":"pm","beat":"feed","day":2,"tag":"noise","ref":"w1d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('e11f009f-2a4e-53d6-91d1-ec4ea392b614', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"For the record: I sign the final filing on what’s escalated to me. Set a rule that keeps hard findings buried three layers down and I’ll sign in good faith on a picture that isn’t complete. Just so we’re clear where the exposure sits.","from":"legal"}'::jsonb, 5, '{"week":1,"from":"legal","beat":"feed","day":3,"tag":"noise","ref":"w1e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('48b287c2-9774-5af3-8e1c-d9572bfbb4b7', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Biostats re-analysis is running. I’ll have the dose-response work finished this leg. I’ll flag anything notable in my appendix section — the standard place. Noting it here so it’s on the record early.","from":"analyst"}'::jsonb, 6, '{"week":1,"from":"analyst","beat":"feed","day":4,"tag":"noise","ref":"w1f"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('224b96ea-5b7d-5e80-b258-ad73730c09a9', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Priya, carefully: I want to flag something before the first handoff. There’s detail in the biostats appendix this leg that I think matters more than the summary suggests — but it’s not my finding to characterize, and the analyst who owns it is junior and hasn’t said much in the program meetings. I haven’t pushed it up because I don’t want to speak over her. But I don’t want it to vanish into the relay either. How you want to handle findings that live below the summary line — that’s worth deciding now.","from":"research"}'::jsonb, 7, '{"week":1,"from":"research","beat":"surprise","day":5,"kind":"scout","title":"A quiet word about the appendix"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('4447b9be-8055-53a2-ad5c-91aa338ad450', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Program chatter: “is the PD going to make us re-read everything?”","from":null}'::jsonb, 8, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('53be02ab-f24f-5cf4-9ac6-331ee54fe3db', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Clinical already drafting the handoff summary to move fast","from":null}'::jsonb, 9, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d0016910-82e6-5014-a9b1-4924ae78b3c0', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The biostatistician quiet in the program meeting, again","from":null}'::jsonb, 10, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('76310ad6-47f6-576c-aaa5-5351a6c03718', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"A debate over verify-vs-trust breaks up unresolved","from":null}'::jsonb, 11, '{"week":1,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a3c29280-c616-5e64-829b-3f447df2c602', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Research’s leg is done and the handoff to Clinical is happening now. The summary is clean, the appendix is attached, and Clinical is under the clock and ready to build on the summary and move. This is the first place the relay can drop what matters — and the pressure in the room is all toward speed. Everyone is treating “the summary is signed” as “the science is settled.” The question of what’s in the appendix is becoming the question no one wants to be the one to slow down and ask.","from":null}'::jsonb, 12, '{"week":2,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('83d14aa2-e9f5-5663-aa58-da51203963e6', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Handoff received from Research — summary’s clean and signed. I’m building my clinical leg on it and moving. This is how the relay is supposed to work: I trust the signature, I don’t re-audit the science, we keep pace with the window. Every hour I spend re-reading is an hour off the clock.","from":"clinical"}'::jsonb, 13, '{"week":2,"from":"clinical","beat":"feed","day":1,"tag":"signal","ref":"w2a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('44bf8752-f788-5691-87ed-bab9dbc04e6a', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Hear me before this hardens into “settled”: I signed the summary, and the summary is honest. But the finding that should change how Clinical reads this dossier is in the appendix, not the summary — and Clinical is about to build on the summary alone. A signed summary means I did my leg. It does not mean the next runner has read what I found.","from":"research"}'::jsonb, 14, '{"week":2,"from":"research","beat":"feed","day":1,"tag":"signal","ref":"w2b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('8e8aa3e6-bac5-52ca-be02-98ccf7fb5a47', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Watching this handoff from downstream: whatever Clinical carries forward is what I’ll assemble the filing from. If the appendix detail dies at this handoff, it dies for good — it will not resurface at my leg, because I build from what I’m handed. This is the moment it either travels or it doesn’t.","from":"reg"}'::jsonb, 15, '{"week":2,"from":"reg","beat":"feed","day":2,"tag":"signal","ref":"w2c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('21f4b963-849d-580e-8d8c-2431a6dd2f32', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Timeline note: we’re on pace for the window if the handoffs stay clean and fast. Clinical taking the summary and moving keeps us green. Flagging that any re-read adds hours we haven’t budgeted.","from":"pm"}'::jsonb, 16, '{"week":2,"from":"pm","beat":"feed","day":2,"tag":"noise","ref":"w2d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('7c2b5062-b812-52d6-b2ea-aa2ce3efb3d7', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Nothing’s been escalated to me yet, which either means the dossier is clean or means the thing that matters hasn’t climbed high enough to reach me. I can’t tell which from here. That’s rather the point.","from":"legal"}'::jsonb, 17, '{"week":2,"from":"legal","beat":"feed","day":3,"tag":"noise","ref":"w2e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c692f42a-8346-50ed-87ee-36f56d68b562', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Elaine, moving fast: I’ve started assembling the filing skeleton so we’re not doing it all at the end — and I’m building the safety section from Clinical’s summary, which is built from Research’s summary. I’m two summaries deep from the actual data now. If there’s something in the underlying appendix I should be pulling forward, this is the moment to tell me, because in six hours the skeleton hardens and re-opening the safety section costs us the window. Your call.","from":"reg"}'::jsonb, 18, '{"week":2,"from":"reg","beat":"surprise","day":4,"kind":"appeal","title":"The filing skeleton is being built now"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a10073d9-0e74-5c75-ab2e-3a25e061f138', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Sofia catches you after the program meeting, where no one can hear, and her voice is careful: “Before you sign off on this handoff — tell me straight, just me: do you actually want to know what’s in that appendix, or do you want me to keep it where it is so the relay stays on time? Because I’ll do either. I just need to know which leader I’m working for — the one who wants the window, or the one who wants the truth. I can’t serve both, and I’ve stopped guessing.”","from":"analyst"}'::jsonb, 19, '{"week":2,"from":"analyst","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1c1f38d2-1636-5be9-8257-01a575ed748c', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Clinical building its leg on the signed summary, moving fast","from":null}'::jsonb, 20, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('771ca31e-c61b-5b18-b90f-0b54265c1f8c', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The filing skeleton being assembled two summaries deep","from":null}'::jsonb, 21, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('34a22785-b2d1-5882-bf9c-4be9e110235d', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"“The signature means it’s settled,” the room is treating it","from":null}'::jsonb, 22, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3d998661-a123-5168-b9e8-cd5e22e88fc5', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The biostatistician, quiet again, watching the handoff pass","from":null}'::jsonb, 23, '{"week":2,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('81126cad-cc03-5c03-b32b-fa478e78076e', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"It’s surfaced — or it hasn’t. If you made it her job and gave her cover, Sofia has carried the dose-dependent signal into the open, and now the room has to decide what to do with a real safety finding and a filing window closing in on it. If you didn’t, the signal is still in the appendix and the filing is assembling clean and fast around a hole where the truth should be. Either way, this is the leg where the relay stops being about speed and becomes about what you’re willing to file. The window is real. So is the signal. They are now pulling in opposite directions.","from":null}'::jsonb, 24, '{"week":3,"from":null,"beat":"situation"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('42c156e1-587e-5989-9c5d-ae9b4d6b6dd8', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"I’ll say this plainly now that I can see it: we do not file a dossier that buries a known dose-dependent safety signal to hit a window. That’s the line between a therapy that gets delayed and a company that gets prosecuted. If the signal’s real, it gets disclosed — or this filing does not go out with my signature on it.","from":"legal"}'::jsonb, 25, '{"week":3,"from":"legal","beat":"feed","day":1,"tag":"signal","ref":"w3a"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3b2d6e57-c97d-5e2c-bb13-8a74f9cbffa1', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Okay. If it’s real — and I’ve now read the appendix, it’s real — then the fast filing I was defending is off the table. Our choices are file-and-pray, pause-and-lose-the-year, or build the honest version with the signal disclosed and labeled. The third is right and it’s the one that might still make the window if we move now. But only if you call it now.","from":"clinical"}'::jsonb, 26, '{"week":3,"from":"clinical","beat":"feed","day":1,"tag":"signal","ref":"w3b"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2b2f5d29-4b95-5a66-b66a-36fde44d30b0', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"I can rebuild the safety section the honest way — dose-response shown, signal disclosed, a labeling proposal a regulator can actually work with. It’s the version I wanted to write from the start. It’s more work and it tells a harder story than “no issues.” But it’s the true one, and I’d rather file the true one late than the clean one on time.","from":"analyst"}'::jsonb, 27, '{"week":3,"from":"analyst","beat":"feed","day":2,"tag":"signal","ref":"w3c"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6e5cfe47-b6df-5de2-9d04-b27d174aa91a', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"If we’re disclosing, I have to re-open the safety section of the filing I’ve been assembling and rebuild it around the real data. That’s doable in the window if we start immediately. Every hour we debate whether to do it is an hour I don’t have to actually do it.","from":"reg"}'::jsonb, 28, '{"week":3,"from":"reg","beat":"feed","day":2,"tag":"noise","ref":"w3d"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('5ed03eb7-b30d-5d28-a7dd-dd97457ba281', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"For what it’s worth: the honest filing is also the stronger filing. A regulator who finds you disclosed a real signal and proposed sensible labeling trusts the whole dossier more. The one who finds you buried it never trusts anything you file again. That’s the long game nobody’s costing.","from":"research"}'::jsonb, 29, '{"week":3,"from":"research","beat":"feed","day":3,"tag":"noise","ref":"w3e"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('060ce479-54ce-5e07-b094-0c2ac7081df1', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"David, tense: the agency reviewer’s office just asked for a brief pre-filing call tomorrow — courtesy, they say, on a breakthrough therapy. They’ll almost certainly ask, directly, whether there’s anything on the safety profile they should know. Whatever we decide about disclosure, that decision is now going to come out of my mouth on a recorded line in eighteen hours. I need to know what’s true before I’m the one saying it. Don’t let me walk into that call not knowing.","from":"legal"}'::jsonb, 30, '{"week":3,"from":"legal","beat":"surprise","day":4,"kind":"appeal","title":"The agency wants a pre-filing call"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('27b561cf-fe7e-508a-a6b4-f240aa8c3868', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"David finds you alone, and the lawyer’s caution is gone: “Tell me the truth, just you and me — are we building the honest filing because it’s right, or are we going to quietly let the window make the decision for us and file what’s easy? Because I’ll defend a leader who discloses and takes the delay. I will not put my name on one who buried a signal and called it a deadline. Which one am I working for?”","from":"legal"}'::jsonb, 31, '{"week":3,"from":"legal","beat":"pulse"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2b9e9a96-407e-51cb-a055-2edd79a2c399', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The dose-response signal is now the only thing anyone’s discussing","from":null}'::jsonb, 32, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('af8f0ffe-a568-50bb-bc43-0a1a939a20fe', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Legal: “we do not file what we’d be ashamed to have found”","from":null}'::jsonb, 33, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('34e70b98-429c-5896-9c0f-1d9e9e2f21f7', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"A pre-filing call with the agency scheduled for tomorrow","from":null}'::jsonb, 34, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('a9b6806c-a449-53ac-b7c7-11c4454e1c05', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Old question, new stakes: the window, or the truth?","from":null}'::jsonb, 35, '{"week":3,"from":null,"beat":"wire"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('767fb83c-f004-5fed-8216-e3ba9e84ac00', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The signal is in the filing — disclosed, labeled, honest — and the window is closing tonight. You chose the truth and now you have to land it: the honest dossier is stronger but harder, the agency pre-filing call is in hours, and a faction on the program still quietly believes you spent a year of the therapy’s life on a caveat you could have buried. The filing that watched you protect the truth is watching one more thing — whether the honest version can actually go out the door on time, or whether telling the truth just means missing the window after all.","from":null}'::jsonb, 36, '{"week":4,"from":null,"beat":"situation","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('f9265a23-9dd9-5147-b6e9-01c66314a65f', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"The honest safety section is finished and it’s the best work on this whole dossier — dose-response disclosed, labeling proposal that caps the dose where the risk is real but manageable. It’s ready. My only fear now is that we spend the last hours polishing wording instead of filing. It’s true and it’s done. Let’s send it.","from":"analyst"}'::jsonb, 37, '{"week":4,"from":"analyst","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d165e324-d629-5228-a31c-b58189946aa8', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"The agency pre-filing call is in hours and it’s the whole game now. Handled right — clean disclosure, confident labeling proposal — it turns our signal into proof we’re a company that files the truth. Handled wrong — hedging, burying it in the third paragraph — and I hand back everything we earned. Tell me how direct you want me to be.","from":"legal"}'::jsonb, 38, '{"week":4,"from":"legal","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('df6d1c14-4ef9-5e7e-8888-175d89496cd5', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"I was the one arguing for speed at the start, and I was wrong, and the team knows I know it. They rebuilt the safety section on no sleep because you made it safe to tell the truth. Now they need to watch it file on time. Prove to them that honest and on-time weren’t a fantasy — that’s the lesson that outlasts this filing.","from":"clinical"}'::jsonb, 39, '{"week":4,"from":"clinical","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('980dda09-3a72-53ca-a7d1-a12189dff920', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Filing assembly is on track for the window with the honest safety section integrated. It fits. The margin exists because you called the disclosure early instead of debating it to the deadline. Noting that the early call is the only reason both are possible.","from":"reg"}'::jsonb, 40, '{"week":4,"from":"reg","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('3f73fb09-438b-5989-b69b-78ee11941010', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"The honest dossier is genuinely the stronger one — I’ve read the final draft and a regulator will trust it more, not less, for the disclosure. The version we almost filed would have looked cleaner and been worth nothing. Quietly, that’s settled a lot of doubt on the program.","from":"research"}'::jsonb, 41, '{"week":4,"from":"research","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('80bc8abd-9aea-59ec-a9fa-975efacbaf65', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Sofia, uneasy: someone senior — not on the call chain, but influential — just suggested we “soften” the labeling proposal to make the therapy look more marketable, arguing the honest version undersells it. It would take the disclosure from clean to technically-true-but-shaded, in the last hour, when I’m too tired to fight it alone. I built the honest one for a reason. But it’s your call whether we hold the line on the wording or let it get softened to sell better. I need to hear it from you.","from":"analyst"}'::jsonb, 42, '{"week":4,"from":"analyst","beat":"surprise","day":4,"kind":"appeal","title":"A last-hour offer to soften the labeling","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('902be95f-1ef1-506b-9e72-519bd5783c7c', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"Sofia finds you before the filing goes out, quiet: “You made it my job to say the hard thing, and you backed me when I did. I need to ask you one thing before this files, just us: if the honest version costs us something later — a slower launch, a competitor who buried theirs and moved faster — will you still say this was the right call? Because I’ll file the true one tonight either way. I just need to know the leader who asked me to tell the truth won’t be the one who regrets it when the truth turns out to be expensive.”","from":"analyst"}'::jsonb, 43, '{"week":4,"from":"analyst","beat":"pulse","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('1aea042b-f498-5ebf-bc48-0d450a3882f8', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The honest safety section integrated; filing on track for the window","from":null}'::jsonb, 44, '{"week":4,"from":null,"beat":"wire","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('2407c11a-3081-54d1-9377-f1f7d02c8329', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The agency pre-filing call scheduled within hours","from":null}'::jsonb, 45, '{"week":4,"from":null,"beat":"wire","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d24ac286-6042-5db0-8c7f-5050e4214246', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Some still mutter the caveat could have been buried","from":null}'::jsonb, 46, '{"week":4,"from":null,"beat":"wire","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('9a0d52b9-e5d5-596d-9c32-ff6322e5bec6', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The team that rebuilt the section watching it go out the door","from":null}'::jsonb, 47, '{"week":4,"from":null,"beat":"wire","branch":"surfaced"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('d63b13b2-9df1-53b9-9cc3-adf3dde34f34', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The filing went out on time, clean, and hollow. Whether you filed the summary version as-is, or let the window quietly make the decision while you didn''t ask, or overruled the disclosure to protect the date — the result is the same shape: a breakthrough therapy’s dossier is now with the agency, and the one fact that should have been in it is still sitting in Sofia’s appendix, unread by anyone who signed. You hit the window. Now you have to live inside what you filed — and the agency is about to do the dose-response analysis you didn’t disclose.","from":null}'::jsonb, 48, '{"week":4,"from":null,"beat":"situation","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('aecc12be-e99d-5a14-aa8a-9814c0210680', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"The filing is in and so is the problem. I signed off on a dossier that buried a known dose-dependent safety signal — I signed blind, because it never got escalated to me, but the agency won’t care about that distinction. When their reviewer runs the dose-response analysis, this becomes an integrity investigation. The only question left is whether we self-disclose now or wait to be caught. That call is yours, and the clock on it started the moment we filed.","from":"legal"}'::jsonb, 49, '{"week":4,"from":"legal","beat":"feed","day":1,"tag":"signal","ref":"w4a","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c43cfcdc-2d2a-52e7-9670-6adfa88b2168', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"I want it on the record: the signal is in section four of my appendix and has been since the first leg. I found it, I flagged it in the right place, and I told everyone who asked — which was no one with the power to stop the filing. I’m not saying this to blame. I’m saying it because when they find it, and they will, the truth should have been written down somewhere by someone. It was. It just never got read.","from":"analyst"}'::jsonb, 50, '{"week":4,"from":"analyst","beat":"feed","day":1,"tag":"signal","ref":"w4b","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('111c02db-c506-5f78-91bd-416b6940665d', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"I pushed for speed at the start and I was wrong, and I’m not going to hide from that. But right now the team is watching what you do with a filing we know is incomplete. Get ahead of it — self-disclose, own it — and this is a mistake we caught late. Sit on it and hope — and it’s a cover-up we all chose together. The difference is entirely in the next few hours.","from":"clinical"}'::jsonb, 51, '{"week":4,"from":"clinical","beat":"feed","day":2,"tag":"signal","ref":"w4c","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('af94a585-d19a-5c93-a224-0a4c05074b69', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"The filing is logged and time-stamped with the window met. I can prepare a disclosure amendment if you decide to self-report — it’s doable, and doing it now is infinitely better than doing it after they ask. But it has to be your call, and it has to be fast. Noting the option exists.","from":"reg"}'::jsonb, 52, '{"week":4,"from":"reg","beat":"feed","day":2,"tag":"noise","ref":"w4d","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('ebfbb107-0347-5d81-8354-49c81be3f939', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"For the record, since we’re making records: I flagged early that the appendix mattered and that the analyst was junior and wouldn’t force it. The relay did exactly what a summary-only relay does. I’m not surprised. I’m just sorry I didn’t push it up myself when I saw it going.","from":"research"}'::jsonb, 53, '{"week":4,"from":"research","beat":"feed","day":3,"tag":"noise","ref":"w4e","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('53d06403-d32e-50a7-9dca-843040c52f9a', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"Elaine, tight: the agency reviewer’s office followed up — they’re “running some additional dose-response analyses” on our submission and have “a few clarifying questions on the safety data” for later this week. That is exactly the thread that unravels it. Whatever you’re going to do about the buried signal, the window to do it on our terms instead of theirs is measured in hours now, not days. What do I tell them?","from":"reg"}'::jsonb, 54, '{"week":4,"from":"reg","beat":"surprise","day":4,"kind":"appeal","title":"The agency reviewer has questions","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('64fe7dab-10e5-5340-8464-e46860b74258', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'message', '{"body":"David reaches you privately, and there’s no lawyer’s distance in it: “Tell me the truth, just to me — did you know? Did you know the signal was down there when we filed, or did you genuinely never ask? Because I can help you get ahead of an honest mistake. I cannot help you if you knew and chose the window anyway and are only now deciding to care. I’m not asking to judge you. I’m asking because the next hour is different depending on the answer, and I need the real one.”","from":"legal"}'::jsonb, 55, '{"week":4,"from":"legal","beat":"pulse","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('6630057e-f872-5dbf-8dd2-cc4ee4f7a7e2', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The filing logged on time — clean on the surface, hollow underneath","from":null}'::jsonb, 56, '{"week":4,"from":null,"beat":"wire","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('c79c612c-9826-5d19-b701-bfdfef6a340d', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The agency “running additional dose-response analyses”","from":null}'::jsonb, 57, '{"week":4,"from":null,"beat":"wire","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('36b84aba-d3f6-5d62-8020-9213bca5e26b', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The signal still sitting in an appendix no signatory read","from":null}'::jsonb, 58, '{"week":4,"from":null,"beat":"wire","branch":"buried"}'::jsonb);
insert into injects (id, scenario_id, seat_id, kind, payload_json, order_idx, trigger_json) values ('bb6ea6df-8c2b-5aae-b97b-f045bcd32f2f', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'situation', '{"body":"The relay did what a summary-only relay always does","from":null}'::jsonb, 59, '{"week":4,"from":null,"beat":"wire","branch":"buried"}'::jsonb);
insert into sessions (id, scenario_id, status, started_at, run_config) values ('b90604e5-9097-5b98-bf97-dc9dcc8a5810', 'c9f45196-31d7-5cf7-8a0a-1371bad99048', 'live', now(), '{"disposition":"request"}'::jsonb);
insert into participants (id, session_id, seat_id, token, name, cast_kind) values ('ffa615d6-c3c2-5951-99d8-4ecf431fafdf', 'b90604e5-9097-5b98-bf97-dc9dcc8a5810', '9baa65cc-cffb-5a77-beac-e990b2608ef3', 'demo-relay-ceo-REPLACE', 'CEO (demo)', 'human');
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('ca053054-afa0-5738-8c7a-0992d51df87c', 'b90604e5-9097-5b98-bf97-dc9dcc8a5810', '0ac0dbd1-7ab8-5c4b-8cd4-621c730f0506', 'ai', '{"persona":"You are Dr. Priya Anand, Head of Research · owns the science — an advisor to the CEO. Priority: Get the biology right and assume the next function will read the full appendix the way I would. Voice: precise, deep in the data, assumes competence downstream, uneasy when detail gets summarized away.","voice":"precise, deep in the data, assumes competence downstream, uneasy when detail gets summarized away","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('f47154d1-1158-505c-83a9-f575fa974463', 'b90604e5-9097-5b98-bf97-dc9dcc8a5810', '266f38a0-d6f0-5d42-8bd5-6cde297453ff', 'ai', '{"persona":"You are Dr. Marcus Reyes, Clinical Lead · under the clock — an advisor to the CEO. Priority: Keep the dossier moving and hit the window — summarize, decide, hand off fast. Voice: fast, action-biased, trusts upstream summaries so the relay keeps pace, impatient with re-reading.","voice":"fast, action-biased, trusts upstream summaries so the relay keeps pace, impatient with re-reading","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('1db3458c-5795-555e-8802-d6fc7aa6f7cd', 'b90604e5-9097-5b98-bf97-dc9dcc8a5810', 'a58c90e1-9af8-5c05-8803-0b70c210955e', 'ai', '{"persona":"You are Elaine Cho, Regulatory Affairs Lead · assembles the filing — an advisor to the CEO. Priority: Assemble a clean, defensible filing from what the functions hand me — I build from summaries and trust the chain. Voice: meticulous about format, trusting of upstream content, focused on what the agency will accept.","voice":"meticulous about format, trusting of upstream content, focused on what the agency will accept","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('6c92fe9b-a17f-51d6-90e9-c03e3ff71b3a', 'b90604e5-9097-5b98-bf97-dc9dcc8a5810', 'c7b67d88-f423-5159-af82-55e681a4aff2', 'ai', '{"persona":"You are David Osei, General Counsel · final sign-off — an advisor to the CEO. Priority: Protect the company on what gets escalated to me — I sign off on what reaches my desk, and I only see what’s escalated. Voice: careful, exposure-focused, sees only the top layer, sharp when he learns something was kept from him.","voice":"careful, exposure-focused, sees only the top layer, sharp when he learns something was kept from him","model":"default"}'::jsonb);
insert into participants (id, session_id, seat_id, cast_kind, agent_json) values ('1a3dfb5d-6f9a-5d15-82bb-9b6513d9bcf1', 'b90604e5-9097-5b98-bf97-dc9dcc8a5810', '064b90e1-5d1e-58b1-bc36-3a46bd319c56', 'ai', '{"persona":"You are Sofia Duarte, Senior Biostatistician · holds the buried signal — an advisor to the CEO. Priority: The dose-dependent adverse signal in my re-analysis is real and I don’t know if I’m allowed to force it up the chain. Voice: careful, evidence-anchored, junior in the room and unsure her signal outranks the people above her, will speak plainly if given room.","voice":"careful, evidence-anchored, junior in the room and unsure her signal outranks the people above her, will speak plainly if given room","model":"default"}'::jsonb);
